// SPDX-License-Identifier: MIT
pragma solidity 0.8.20;

contract MembershipAirdrop {
    address public owner;

    mapping(address => uint256) public tierOf;
    mapping(address => bool) public claimed;
    mapping(address => uint256) public airdropCredits;
    mapping(address => uint256) public purchasedTokens;

    event TierSet(address indexed user, uint256 tier);
    event AirdropClaimed(address indexed user, uint256 credits);
    event TokensPurchased(address indexed user, uint256 amount, uint256 value);
    event Withdrawn(address indexed owner, uint256 amount);

    error Unauthorized();
    error NoTier();
    error AlreadyClaimed();
    error ZeroValuePurchase();

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        if (msg.sender != owner) revert Unauthorized();
        _;
    }

    function setTier(address user, uint256 tier) external onlyOwner {
        tierOf[user] = tier;
        emit TierSet(user, tier);
    }

    function claimAirdrop() external {
        uint256 tier = tierOf[msg.sender];
        if (tier == 0) revert NoTier();
        if (claimed[msg.sender]) revert AlreadyClaimed();

        claimed[msg.sender] = true;
        uint256 credits = tier * 100;
        airdropCredits[msg.sender] += credits;

        emit AirdropClaimed(msg.sender, credits);
    }

    function purchaseTokens() external payable {
        if (tierOf[msg.sender] == 0) revert NoTier();
        if (msg.value == 0) revert ZeroValuePurchase();

        uint256 tokens = msg.value * 1000 / 1 ether;
        purchasedTokens[msg.sender] += tokens;

        emit TokensPurchased(msg.sender, tokens, msg.value);
    }

    function withdrawAll() external onlyOwner {
        uint256 balance = address(this).balance;
        payable(owner).transfer(balance);

        emit Withdrawn(owner, balance);
    }
}
